# Audit: list all custom roles with their Actions and NotActions
Get-AzRoleDefinition | Where-Object { $_.IsCustom } | ForEach-Object {
    [PSCustomObject]@{
        Name = $_.Name
        ActionCount = $_.Actions.Count
        NotActionCount = $_.NotActions.Count
        UsesWildcard = ($_.Actions | Where-Object { $_ -match '\*' }).Count -gt 0
        HasNotActions = $_.NotActions.Count -gt 0
        Assignments = (Get-AzRoleAssignment -RoleDefinitionId $_.Id).Count
    }
} | Format-Table -AutoSize

# Find roles with overly broad wildcards (Actions: ['*'])
Get-AzRoleDefinition | Where-Object {
    $_.IsCustom -and $_.Actions -contains '*'
} | Select-Object Name, Description

# Find roles where NotActions overlaps with what another role grants
# (potential confusion about intent)
$customRoles = Get-AzRoleDefinition | Where-Object { $_.IsCustom }
foreach ($role in $customRoles) {
    if ($role.NotActions.Count -gt 0) {
        Write-Host "$($role.Name) NotActions:"
        $role.NotActions | ForEach-Object { Write-Host "  - $_" }
    }
}

# Compare effective permissions between two custom roles

function Get-EffectiveActions {
    param($RoleName)
    $role = Get-AzRoleDefinition -Name $RoleName
    $allOps = @()
    foreach ($action in $role.Actions) {
        if ($action -match '\*') {
            # Expand wildcard
            $expanded = Get-AzProviderOperation ($action -replace '\*.*$', '*') |
                Where-Object { $_.Operation -like ($action -replace '\*', '*') }
            $allOps += $expanded.Operation
        } else {
            $allOps += $action
        }
    }
    # Subtract NotActions
    $notActionsExpanded = @()
    foreach ($na in $role.NotActions) {
        $notActionsExpanded += $allOps | Where-Object { $_ -like ($na -replace '\*','*') }
    }
    return $allOps | Where-Object { $_ -notin $notActionsExpanded } | Sort-Object -Unique
}

# Usage
$roleAOps = Get-EffectiveActions 'Virtual Machine Operator'
$roleBOps = Get-EffectiveActions 'VM Start Operator'

# Operations in A but not B (role A is broader)
Compare-Object $roleAOps $roleBOps | Where-Object { $_.SideIndicator -eq '<=' } |
    Select-Object -ExpandProperty InputObject
